import streamlit as st
import pandas as pd
from datetime import datetime
import json, os, base64
from io import BytesIO
import plotly.express as px

# ================= CONFIGURAÇÃO DA PÁGINA =================
st.set_page_config(
    page_title="USER LOG",
    page_icon="🔼",
    layout="wide",
    initial_sidebar_state="expanded"
)

# ================= LOGO EMBUTIDO =================
LOGO_B64 = ""

def get_logo_html(width=220):
    return f'''<img src="data:image/png;base64,{LOGO_B64}"
        style="width:{width}px;border-radius:10px;object-fit:cover;display:block;margin:0 auto 0.5rem auto">'''

# ================= PERSISTÊNCIA =================
DATA_FILE = "userlog_data.json"

def carregar_dados():
    if os.path.exists(DATA_FILE):
        with open(DATA_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    return {}

def salvar_dados():
    dados = {
        "clientes": st.session_state.clientes,
        "motoristas": st.session_state.motoristas,
        "empresas": st.session_state.empresas,
        "cargas": st.session_state.cargas,
        "agendamentos": st.session_state.agendamentos,
        "pagamentos": st.session_state.pagamentos,
        "config_empresa": st.session_state.config_empresa,
    }
    with open(DATA_FILE, "w", encoding="utf-8") as f:
        json.dump(dados, f, ensure_ascii=False, indent=2)

